import{_ as a,o as r,c as i,a3 as n}from"./chunks/framework.oxq6d-og.js";const h=JSON.parse('{"title":"Neden NThread?","description":"","frontmatter":{},"headers":[],"relativePath":"nthread/overview.md","filePath":"nthread/overview.md"}'),d={name:"nthread/overview.md"};function l(t,e,o,s,c,m){return r(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="neden-nthread" tabindex="-1">Neden NThread? <a class="header-anchor" href="#neden-nthread" aria-label="Permalink to &quot;Neden NThread?&quot;">​</a></h1><p><code>NThread</code>, yeni bir uzak thread oluşturmak yerine hedef process&#39;te zaten yaşayan <strong>tek</strong> bir OS thread&#39;ini geçici olarak yönlendirir. Bu, <code>CreateRemoteThread</code> kullanmayan bir çağrı yürütme modelidir; hedefe hiç bellek tahsisi yapılmadığı anlamına gelmez. Accessor zinciri ve dörtten fazla parametreli çağrılar hedefte çalışma belleği veya küçük stub&#39;lar kullanabilir.</p><h2 id="varsayılan-kullanım-modeli" tabindex="-1">Varsayılan kullanım modeli <a class="header-anchor" href="#varsayılan-kullanım-modeli" aria-label="Permalink to &quot;Varsayılan kullanım modeli&quot;">​</a></h2><p>Uygulama tarafında doğrudan <code>NThread</code> kurmak çoğu zaman gerekmez. <code>createAccessor(pid)</code> varsayılan olarak process&#39;teki aday thread&#39;leri yarışa sokar, ilk başarılı yönlendirmeyi seçer ve NThread üzerinde kurulu tam accessor zincirini döndürür. Bu accessor ile <code>alloc</code>, <code>read</code>, <code>write</code> ve <code>call</code> aynı yürütme mekanizmasını kullanır.</p><p>Belirli bir thread seçmek, özel bir root accessor kurmak veya düşük seviye context işlemlerine erişmek ileri seviye kullanım alanıdır. Bu durumda thread ve accessor yaşam döngüsünün sorumluluğu çağırandadır.</p><h2 id="ne-saglar" tabindex="-1">Ne sağlar? <a class="header-anchor" href="#ne-saglar" aria-label="Permalink to &quot;Ne sağlar?&quot;">​</a></h2><ul><li>Hedefte yaşayan bir thread üzerinde uzaktaki çağrı çalıştırır.</li><li>Çağrı bitince thread&#39;i spin park noktasına döndürür; dönüş değeri context&#39;ten okunur.</li><li>Deinit sırasında başlangıçta kaydedilen genel amaçlı, control ve XMM context&#39;ini geri uygular.</li><li>İlk dört parametre, stack parametreleri ve dönüş değerleri için NThread&#39;in desteklediği Windows x64 ABI düzenini kurar.</li></ul><h2 id="ne-garanti-etmez" tabindex="-1">Ne garanti etmez? <a class="header-anchor" href="#ne-garanti-etmez" aria-label="Permalink to &quot;Ne garanti etmez?&quot;">​</a></h2><p>NThread, seçilen thread&#39;in o anda güvenle durdurulup tekrar yürütülebileceğini garanti edemez. Thread bir lock, loader lock veya uygulamaya özgü kritik kaynak tutuyor olabilir; fonksiyon thread-local bağlam bekliyor ya da hiç dönmüyor olabilir. Yarışın bir thread seçmesi de bu semantik riskleri ortadan kaldırmaz.</p><p>NThread görünmez veya risksiz değildir. Yeni thread oluşturmamak, mimari bir tercihtir; hedefin davranışını doğru seçme yükünü kullanıcıdan kaldırmaz. Devam etmeden önce <a href="/exoproc/previews/feature-docs/nthread/thread-selection">thread seçimi</a>, <a href="/exoproc/previews/feature-docs/nthread/call-lifecycle">çağrı yaşam döngüsü</a> ve <a href="/exoproc/previews/feature-docs/nthread/failure-modes">hata sınırlarını</a> okuyun.</p>',10)])])}const k=a(d,[["render",l]]);export{h as __pageData,k as default};
